def seed_documents(db):
    if db.query(Document).count() > 0:
        print("Documents already seeded, skipping.")
        return

    sectors = {s.name: s.id for s in db.query(Sector).all()}

    for d in DOCUMENT_CONTENT:
        sid = sectors.get(d.get("sector")) if d.get("sector") else None
        chash = _hash(d["content"])

        doc = Document(
            title=d["title"],
            content=d["content"],
            content_hash=chash,
            doc_type=d["doc_type"],
            sector_id=sid,
            published_at=NOW - timedelta(days=random.randint(1, 365)),
            metadata_={"source": "seed", "sector": d.get("sector", "general")},
        )
        db.add(doc)

    db.commit()
    count = len(DOCUMENT_CONTENT)
    print(f"Seeded {count} documents.")

    # Generate embeddings if RAG engine is available
    if HAS_RAG and _rag:
        print("Generating embeddings for seeded documents...")
        docs = db.query(Document).filter(Document.embedding_stored == False).all()  # noqa: E712
        for i, doc in enumerate(docs):
            try:
                _rag.ingest_document(doc, db)
                if (i + 1) % 10 == 0:
                    print(f"  Embedded {i + 1}/{len(docs)} documents...")
            except Exception as exc:
                print(f"  Warning: Failed to embed '{doc.title[:50]}': {exc}")
        print("Embedding complete.")


