def seed_test_user(db):
    if db.query(User).filter(User.email == "test@innovisa.ai").first():
        print("Test user already exists, skipping.")
        return

    user = User(
        email="test@innovisa.ai",
        hashed_password=hash_password("InnoVisaTest2024!"),
        full_name="Test User",
        onboarding_data={
            "skills": ["Python", "Machine Learning", "Product Management", "Data Analysis"],
            "interests": ["Healthcare AI", "FinTech", "Sustainability", "IoT"],
            "background": "5 years in software engineering with a focus on AI/ML applications",
            "timeline": "6 months",
        },
        subscription_tier=SubscriptionTier.pro,
    )
    db.add(user)
    db.flush()

    # Save first 5 ideas for this user
    ideas = db.query(Idea).limit(5).all()
    for idea in ideas:
        saved = SavedIdea(
            user_id=user.id,
            idea_id=idea.id,
            user_notes=f"Interesting project idea in {idea.title[:30]} area. Worth exploring further.",
        )
        db.add(saved)

    db.commit()
    print("Seeded test user (test@innovisa.ai / InnoVisaTest2024!) with 5 saved ideas.")


def main():
    print("=" * 60)
    print("InnoVisa AI - Database Seed Script")
    print("=" * 60)

    # Create tables if they don't exist (for first run before alembic)
    Base.metadata.create_all(bind=engine)
    print("Database tables ensured.")

    db = SessionLocal()
    try:
        seed_sectors(db)
        seed_ideas(db)
        seed_documents(db)
        seed_competitions(db)
        seed_test_user(db)
        print("\n" + "=" * 60)
        print("Seeding complete!")
        print(f"  Sectors:      {db.query(Sector).count()}")
        print(f"  Ideas:        {db.query(Idea).count()}")
        print(f"  Documents:    {db.query(Document).count()}")
        print(f"  Competitions: {db.query(Competition).count()}")
        print(f"  Users:        {db.query(User).count()}")
        print("=" * 60)
    finally:
        db.close()


if __name__ == "__main__":
    main()
